descriptor.templateCss:
:host {
    display: block;
    width: 100%;
    height: 100%;
    padding: 0;
    margin: 0;
}

.sensor-container {
    font-family: 'Roboto', Arial, sans-serif;
    background-color: transparent;
    width: 100%;
    height: 100%;
    box-sizing: border-box;
    padding: 8px;
}

.metric-card {
    background-color: #ffffff;
    border-radius: 8px;
    padding: 10px;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 8px;
    border-left: 4px solid #EE7623;
    transition: box-shadow 0.2s ease, border-left-color 0.2s ease;
    height: 100%;
    box-sizing: border-box;
    overflow: hidden;
    position: relative;
}

.metric-card.clickable {
    cursor: pointer;
}

.metric-card.clickable:hover {
    border-left-color: #ff8c42;
}

.tank-container {
    flex: 1;
    width: 100%;
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 0;
    min-width: 0;
    overflow: hidden;
}

.tank-wrapper {
    display: flex;
    flex-direction: row;
    align-items: stretch;
    height: 90%;
    max-width: 100%;
    gap: 4px;
}

.tank-body {
    aspect-ratio: 7 / 12;
    height: 100%;
    width: auto;
    min-width: 0;
    flex-shrink: 1;
    background-color: #e0e0e0;
    border-radius: 8px;
    border: 3px solid #ccc;
    position: relative;
    overflow: hidden;
    box-sizing: border-box;
}

.tank-scale {
    position: relative;
    height: calc(100% - 6px);
    align-self: center;
    min-width: 36px;
    flex-shrink: 0;
}

.scale-tick {
    position: absolute;
    right: 0;
    width: 100%;
    height: 1px;
    display: flex;
    align-items: center;
    justify-content: flex-start;
}

.scale-tick::before {
    content: '';
    display: block;
    width: 6px;
    height: 1px;
    background-color: #9EA1A2;
    margin-right: 3px;
}

.scale-label {
    font-size: 10px;
    color: #9EA1A2;
    line-height: 1;
    white-space: nowrap;
}

.tank-liquid {
    position: absolute;
    bottom: 0;
    left: 0;
    width: 100%;
    height: 0%;
    background-color: #EE7623;
    transition: height 0.5s ease-out, background-color 0.3s ease;
}

.tank-glass {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: linear-gradient(90deg, rgba(255, 255, 255, 0.1) 0%, rgba(255, 255, 255, 0.4) 30%, rgba(255, 255, 255, 0) 100%);
    pointer-events: none;
    z-index: 2;
}

.card-content {
    text-align: center;
    width: 100%;
    flex-shrink: 0;
}

.card-value {
    font-size: 22px;
    font-weight: 700;
    color: #24272A;
    line-height: 1.2;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.card-value .unit {
    font-size: 13px;
    font-weight: 400;
    color: #9EA1A2;
    margin-left: 2px;
}

.card-label {
    font-size: 11px;
    color: #9EA1A2;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    margin-top: 4px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.last-update {
    font-size: 9px;
    color: #9EA1A2;
    position: absolute;
    bottom: 4px;
    right: 8px;
    white-space: nowrap;
}

/* Layout: height <= 90px — hide tank, label, last-update */
.layout-tiny .tank-container,
.layout-tiny .card-label,
.layout-tiny .last-update {
    display: none;
}
.layout-tiny .metric-card {
    justify-content: center;
    padding: 4px 8px;
}

/* Layout: width <= 90px — hide tank, scale, last-update */
.layout-narrow .tank-container,
.layout-narrow .tank-scale,
.layout-narrow .last-update {
    display: none;
}
.layout-narrow .metric-card {
    padding: 4px;
    gap: 2px;
}

/* Hide scale when too narrow or too short */
.hide-scale .tank-scale {
    display: none;
}

